            PrefabPoolManager.GetInstance().ReturnNode(oldKey, scatterSpine.node);
            this.m_scatterAnimationSpines.delete(position);
            scatterSpine = null;
        } else if (scatterSpine) {
            scatterSpine.Stop();
        }
    }
    if (!scatterSpine) {
        let prefabKey = SCATTER_ANIMATION_PREFAB_KEY0;
        if (level === 1) prefabKey = SCATTER_ANIMATION_PREFAB_KEY1;
