        if (scatterSpine.Spine) {
            scatterSpine.Spine.enabled = true;
            scatterSpine.Spine.updateAnimation(0);
        }
    }

    scatterSpine.node.setWorldPosition(this.GetSymbolNodeWorldPos(col, row));
    scatterSpine.node.active = true;

    if (onSpineReady) {
        onSpineReady(scatterSpine);
    }

    // 直接用 sp.Skeleton 播 Stop 動畫
    const spine = scatterSpine.node.getComponentInChildren(sp.Skeleton);
    if (!spine) return;
    spine.enabled = true;
    spine.setAnimation(0, SCATTER_STOP_ANIMATION_SPINE_KEY, false);
    spine.updateAnimation(0);
    await new Promise<void>(resolve => {
        spine.setCompleteListener(() => {
            spine.setCompleteListener(null);
            resolve();
        });
    });


